'use client';

import { useState } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { AuthCard } from '@/components/auth/AuthCard';
import { AuthInput } from '@/components/auth/AuthInput';
import { AuthError } from '@/components/auth/AuthError';
import { registerWithEmail } from '@/services/authService';
import useAuthStore from '@/store/useAuthStore';
import { logInfo } from '@/lib/logger';

interface FormErrors {
  displayName?: string;
  email?: string;
  password?: string;
  confirmPassword?: string;
}

function validate(displayName: string, email: string, password: string, confirmPassword: string): FormErrors {
  const errors: FormErrors = {};
  if (!displayName.trim()) errors.displayName = 'Full name is required.';
  else if (displayName.trim().length < 2) errors.displayName = 'Name must be at least 2 characters.';
  if (!email.trim()) errors.email = 'Email is required.';
  else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) errors.email = 'Enter a valid email address.';
  if (!password) errors.password = 'Password is required.';
  else if (password.length < 6) errors.password = 'Password must be at least 6 characters.';
  if (!confirmPassword) errors.confirmPassword = 'Please confirm your password.';
  else if (password !== confirmPassword) errors.confirmPassword = 'Passwords do not match.';
  return errors;
}

export default function RegisterPage() {
  const router = useRouter();
  const { setUser, setError, error } = useAuthStore();

  const [displayName, setDisplayName]         = useState('');
  const [email, setEmail]                     = useState('');
  const [password, setPassword]               = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [isLoading, setIsLoading]             = useState(false);
  const [formErrors, setFormErrors]           = useState<FormErrors>({});

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError(null);

    const errors = validate(displayName, email, password, confirmPassword);
    if (Object.keys(errors).length > 0) {
      setFormErrors(errors);
      return;
    }
    setFormErrors({});

    setIsLoading(true);
    try {
      logInfo('[RegisterPage] Attempting registration', { email });
      const user = await registerWithEmail(email, password, displayName.trim());
      setUser(user);
      logInfo('[RegisterPage] Registration successful, redirecting');
      router.push('/');
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Registration failed.';
      setError(message);
    } finally {
      setIsLoading(false);
    }
  }

  return (
    <AuthCard
      title="Create your account"
      subtitle="Start sending money between Nigeria and Ghana"
    >
      <form onSubmit={handleSubmit} className="flex flex-col gap-5" noValidate>
        <AuthError message={error} />

        <AuthInput
          id="displayName"
          label="Full name"
          type="text"
          placeholder="Adaeze Okonkwo"
          value={displayName}
          onChange={(v) => { setDisplayName(v); setFormErrors((p) => ({ ...p, displayName: undefined })); }}
          error={formErrors.displayName}
          disabled={isLoading}
          autoComplete="name"
        />

        <AuthInput
          id="email"
          label="Email address"
          type="email"
          placeholder="you@example.com"
          value={email}
          onChange={(v) => { setEmail(v); setFormErrors((p) => ({ ...p, email: undefined })); }}
          error={formErrors.email}
          disabled={isLoading}
          autoComplete="email"
        />

        <AuthInput
          id="password"
          label="Password"
          type="password"
          placeholder="Min. 6 characters"
          value={password}
          onChange={(v) => { setPassword(v); setFormErrors((p) => ({ ...p, password: undefined })); }}
          error={formErrors.password}
          disabled={isLoading}
          autoComplete="new-password"
        />

        <AuthInput
          id="confirmPassword"
          label="Confirm password"
          type="password"
          placeholder="••••••••"
          value={confirmPassword}
          onChange={(v) => { setConfirmPassword(v); setFormErrors((p) => ({ ...p, confirmPassword: undefined })); }}
          error={formErrors.confirmPassword}
          disabled={isLoading}
          autoComplete="new-password"
        />

        <button
          type="submit"
          disabled={isLoading}
          className="flex items-center justify-center gap-2 w-full rounded-xl bg-indigo-600 px-5 py-3 text-sm font-semibold text-white transition-all duration-150 hover:bg-indigo-500 active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-indigo-600/20 mt-1"
        >
          {isLoading ? (
            <>
              <svg className="animate-spin" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                <path d="M21 12a9 9 0 1 1-6.219-8.56" strokeLinecap="round"/>
              </svg>
              Creating account...
            </>
          ) : (
            'Create account'
          )}
        </button>

        <p className="text-center text-[12.5px] text-zinc-600">
          Already have an account?{' '}
          <Link href="/auth/login" className="text-indigo-400 hover:text-indigo-300 transition-colors font-medium">
            Sign in
          </Link>
        </p>
      </form>
    </AuthCard>
  );
}
